import crypto from "crypto";

export const JWT_SECRET = "super-secret-key";

export function hashPassword(password: string): string {
  return crypto.createHash("sha256").update(password).digest("hex");
}

import { Request, Response, NextFunction } from "express";
import jwt from "jsonwebtoken";
import { JWT_SECRET } from "../auth-utils.js";

export function authenticate(
  req: Request,
  res: Response,
  next: NextFunction
): void {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    res.status(401).json({ error: "Unauthorized" });
    return;
  }
  const token = authHeader.slice(7);
  try {
    const payload = jwt.verify(token, JWT_SECRET) as { userId: number };
    req.userId = payload.userId;
    next();
  } catch {
    res.status(401).json({ error: "Unauthorized" });
  }
}

import { Router } from "express";
import jwt from "jsonwebtoken";
import { users, nextId } from "../db.js";
import { JWT_SECRET, hashPassword } from "../auth-utils.js";
import { User } from "../types.js";

const router = Router();

// POST /auth/register - create a new user and return a JWT
router.post("/register", (req, res) => {
  const { username, email, password } = req.body;
  if (!username || !email || !password) {
    res.status(400).json({ error: "username, email, and password are required" });
    return;
  }
  const existing = users.find((u) => u.username === username);
  if (existing) {
    res.status(409).json({ error: "Username already taken" });
    return;
  }
  const newUser: User = {
    id: nextId(users),
    username,
    email,
    password: hashPassword(password),
  };
  users.push(newUser);
  const token = jwt.sign({ userId: newUser.id }, JWT_SECRET, { expiresIn: "1h" });
  res.status(201).json({
    token,
    user: { id: newUser.id, username: newUser.username, email: newUser.email },
  });
});

// POST /auth/login - authenticate and return a JWT
router.post("/login", (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) {
    res.status(400).json({ error: "username and password are required" });
    return;
  }
  const user = users.find((u) => u.username === username);
  if (!user || user.password !== hashPassword(password)) {
    res.status(401).json({ error: "Invalid credentials" });
    return;
  }
  const token = jwt.sign({ userId: user.id }, JWT_SECRET, { expiresIn: "1h" });
  res.status(200).json({
    token,
    user: { id: user.id, username: user.username, email: user.email },
  });
});

export { router as authRouter };

